edits.text:
.app-shell {
	min-height: 100vh;
	background: #f4f7fb;
}

.auth-screen {
	padding: 0;
}

.auth-layout {
	display: grid;
	min-height: 100vh;
}

.login-shell,
.content-panel,
.segment-panel,
.table-shell {
	background: #ffffff;
}

.login-brand-panel {
	display: grid;
	place-items: center;
	padding: 48px 32px;
	background: linear-gradient(180deg, #182236 0%, #1d2639 100%);
	color: #ffffff;
	text-align: center;
	gap: 28px;
}

.login-brand-mark {
	display: grid;
	gap: 14px;
	justify-items: center;
}

.login-brand-logo-image {
	width: min(360px, 100%);
	height: auto;
	object-fit: contain;
	filter: drop-shadow(0 18px 50px rgba(0, 0, 0, 0.24));
}

.login-brand-copy h2,
.login-brand-copy p {
	margin: 0;
	color: #ffffff;
}

.login-brand-copy h2 {
	font-size: clamp(2.8rem, 6vw, 4.2rem);
	font-weight: 800;
	letter-spacing: 0.03em;
}

.login-brand-copy p {
	font-size: 1rem;
	color: rgba(255, 255, 255, 0.76);
	text-transform: uppercase;
	letter-spacing: 0.1em;
}

.login-content-panel {
	display: grid;
	align-content: center;
	justify-items: center;
	padding: 48px 28px;
	background:
		radial-gradient(circle at 10% 10%, rgba(59, 130, 246, 0.08), transparent 24%),
		linear-gradient(180deg, #fdfefe 0%, #f6f8fc 100%);
}

.login-heading-block {
	width: min(540px, 100%);
	margin-bottom: 28px;
	text-align: left;
}

.login-heading-block h1,
.content-panel h1,
.content-panel h2,
.workspace-title {
	margin: 0;
	color: #24324d;
	line-height: 1.1;
}

.login-heading-block h1 {
	font-size: clamp(2.8rem, 5vw, 4.2rem);
	font-weight: 800;
	letter-spacing: -0.04em;
	margin-bottom: 20px;
}

.support-heading {
	font-size: 1.1rem;
	font-weight: 700;
	margin-bottom: 12px;
}

.login-form,
.destination-form {
	display: grid;
	gap: 18px;
	width: min(540px, 100%);
}

.field-group {
	display: grid;
	gap: 8px;
	color: #25334d;
	font-weight: 600;
}

.field-group input,
.field-group textarea,
.search-input,
.page-select {
	width: 100%;
	padding: 15px 18px;
	border: 1px solid #d6ddeb;
	border-radius: 14px;
	background: #ffffff;
	color: #24324d;
	font: inherit;
	box-shadow: 0 6px 18px rgba(37, 51, 77, 0.04);
	transition: border-color 0.2s ease, box-shadow 0.2s ease, transform 0.2s ease;
}

.field-group textarea {
	resize: vertical;
	min-height: 130px;
}

.field-group input:focus,
.field-group textarea:focus,
.search-input:focus,
.page-select:focus {
	outline: none;
	border-color: #2f63e1;
	box-shadow: 0 0 0 4px rgba(47, 99, 225, 0.12);
	transform: translateY(-1px);
}

.primary-button,
.ghost-button,
.bulk-button,
.sidebar-primary-action,
.sidebar-logout-button,
.sidebar-nav-item,
.segment-pill {
	border: 0;
	font: inherit;
	cursor: pointer;
	transition: transform 0.2s ease, box-shadow 0.2s ease, background-color 0.2s ease;
}

.primary-button,
.sidebar-primary-action,
.bulk-button {
	border-radius: 14px;
	padding: 14px 20px;
	font-weight: 700;
	color: #ffffff;
	box-shadow: 0 14px 28px rgba(47, 99, 225, 0.24);
	background: linear-gradient(135deg, #3b6ef3 0%, #2450d8 100%);
}

.bulk-button {
	background: linear-gradient(135deg, #18a957 0%, #148949 100%);
	box-shadow: 0 14px 28px rgba(24, 169, 87, 0.22);
}

.primary-button:hover,
.sidebar-primary-action:hover,
.bulk-button:hover,
.ghost-button:hover,
.sidebar-logout-button:hover,
.segment-pill:hover {
	transform: translateY(-1px);
}

.primary-button:disabled,
.ghost-button:disabled,
.bulk-button:disabled {
	cursor: wait;
	opacity: 0.7;
	transform: none;
}

.ghost-button {
	padding: 11px 14px;
	border-radius: 12px;
	background: #ffffff;
	color: #32435f;
	border: 1px solid #d8dfed;
	font-weight: 700;
	box-shadow: 0 8px 20px rgba(37, 51, 77, 0.04);
}

.ghost-button.danger {
	color: #c93535;
	border-color: rgba(201, 53, 53, 0.25);
	background: #fff8f8;
}

.search-button {
	white-space: nowrap;
}

.error-message {
	color: #c93535;
	font-weight: 600;
	font-size: 0.94rem;
}

.row-error-message {
	grid-column: 1 / -1;
	padding: 12px 14px;
	border-radius: 12px;
	background: #fff4f4;
	border: 1px solid rgba(201, 53, 53, 0.18);
	color: #c93535;
	font-weight: 600;
}

.workspace-shell {
	display: grid;
	min-height: 100vh;
	background: #f4f7fb;
}

.workspace-sidebar {
	display: grid;
	grid-template-rows: auto auto 1fr auto;
	background: linear-gradient(180deg, #182236 0%, #1d2639 100%);
	color: #ffffff;
	min-height: 100vh;
	border-right: 1px solid rgba(255, 255, 255, 0.08);
}

.sidebar-brand-block,
.sidebar-footer {
	padding: 24px 18px;
	border-bottom: 1px solid rgba(255, 255, 255, 0.08);
}

.sidebar-footer {
	border-bottom: 0;
	border-top: 1px solid rgba(255, 255, 255, 0.08);
	align-self: end;
}

.sidebar-brand-mark {
	display: grid;
	gap: 10px;
	padding-bottom: 28px;
}

.sidebar-brand-image {
	width: min(240px, 100%);
	height: auto;
	object-fit: contain;
}

.sidebar-user-block {
	padding-top: 10px;
	font-size: 1rem;
	font-weight: 700;
}

.sidebar-user-greeting {
	margin: 0;
	font-size: 1.05rem;
	color: #ffffff;
}

.sidebar-primary-action {
	margin: 18px 14px;
	display: flex;
	align-items: center;
	justify-content: center;
	gap: 10px;
}

.sidebar-nav {
	display: grid;
	gap: 8px;
	padding: 6px 12px 24px;
	align-content: start;
}

.sidebar-nav-group {
	display: grid;
	gap: 6px;
}

.sidebar-nav-item,
.sidebar-nav-item:link,
.sidebar-nav-item:visited {
	display: flex;
	justify-content: space-between;
	align-items: center;
	min-height: 46px;
	padding: 0 16px;
	border-radius: 12px;
	background: transparent;
	color: rgba(255, 255, 255, 0.82);
	text-decoration: none;
	font-weight: 600;
	text-align: left;
	box-shadow: none;
}

.sidebar-nav-item.active {
	background: rgba(116, 142, 191, 0.28);
	color: #ffffff;
}

.sidebar-nav-toggle {
	width: 100%;
}

.sidebar-chevron {
	font-size: 0.9rem;
	color: rgba(255, 255, 255, 0.7);
}

.sidebar-submenu {
	display: grid;
	gap: 6px;
	padding: 2px 0 8px 16px;
}

.sidebar-submenu-item,
.sidebar-submenu-item:link,
.sidebar-submenu-item:visited {
	display: flex;
	align-items: center;
	min-height: 34px;
	padding: 0 16px;
	border-radius: 10px;
	background: transparent;
	border: 0;
	font: inherit;
	color: rgba(255, 255, 255, 0.66);
	text-decoration: none;
	text-align: left;
	font-weight: 500;
	cursor: pointer;
}

.sidebar-submenu-item.active {
	background: rgba(116, 142, 191, 0.34);
	color: #ffffff;
	font-weight: 700;
}

.sidebar-logout-button {
	width: 100%;
	padding: 12px 14px;
	border-radius: 12px;
	background: transparent;
	color: rgba(255, 255, 255, 0.84);
	text-align: left;
	font-weight: 600;
	border: 1px solid rgba(255, 255, 255, 0.08);
}

.workspace-main-shell {
	display: grid;
	grid-template-rows: auto 1fr;
	min-width: 0;
}

.workspace-header {
	display: flex;
	justify-content: space-between;
	align-items: center;
	gap: 24px;
	padding: 18px 24px;
	background: #ffffff;
	border-bottom: 1px solid #dfe5f1;
	box-shadow: 0 3px 18px rgba(37, 51, 77, 0.04);
	position: sticky;
	top: 0;
	z-index: 10;
}

.workspace-header-main {
	display: flex;
	align-items: center;
	gap: 14px;
	min-width: 0;
}

.gaia-mini-mark-image {
	width: 104px;
	height: 42px;
	object-fit: contain;
}

.workspace-title {
	font-size: clamp(2rem, 3vw, 2.65rem);
	font-weight: 800;
	letter-spacing: -0.04em;
}

.workspace-help-block {
	display: grid;
	justify-items: end;
	gap: 4px;
	font-size: 0.92rem;
	color: #6b7890;
	text-align: right;
}

.workspace-help-block a {
	color: #2f63e1;
	text-decoration: none;
	font-weight: 600;
}

.workspace-content {
	display: grid;
	gap: 24px;
	padding: 28px;
}

.dashboard-grid {
	display: grid;
	gap: 24px;
}

.content-panel {
	padding: 0;
	border: 1px solid #e2e8f3;
	border-radius: 20px;
	box-shadow: 0 18px 50px rgba(37, 51, 77, 0.08);
	overflow: hidden;
}

.content-panel:first-child {
	padding: 28px;
	background: transparent;
	border: 0;
	box-shadow: none;
	overflow: visible;
}

.form-panel {
	padding: 28px;
	align-self: start;
	position: sticky;
	top: 100px;
	background: #ffffff;
	border: 1px solid #e2e8f3;
	box-shadow: 0 18px 50px rgba(37, 51, 77, 0.08);
	border-radius: 22px;
}

.form-section-card {
	display: grid;
	gap: 18px;
	padding: 24px;
	border-radius: 20px;
	border: 1px solid #e2e8f3;
	background: linear-gradient(180deg, #ffffff 0%, #fbfcff 100%);
	box-shadow: 0 16px 40px rgba(37, 51, 77, 0.06);
}

.form-section-title-row {
	display: flex;
	align-items: flex-start;
	gap: 14px;
}

.form-section-icon {
	display: grid;
	place-items: center;
	width: 34px;
	height: 34px;
	border-radius: 10px;
	background: #edf3ff;
	color: #2854db;
	font-size: 1.05rem;
	font-weight: 700;
}

.form-section-title {
	margin: 0 0 4px;
	font-size: 1.55rem;
	font-weight: 800;
	color: #24324d;
}

.form-section-copy {
	font-size: 0.95rem;
	color: #70809c;
}

.destination-form-grid {
	display: grid;
	gap: 18px;
}

.destination-form-grid.two-column {
	grid-template-columns: repeat(2, minmax(0, 1fr));
}

.destination-form-grid.compact-gap {
	gap: 16px;
}

.field-group-hint {
	align-content: start;
}

.destination-preview-panel {
	display: grid;
	gap: 6px;
	min-height: 100%;
	padding: 16px;
	border-radius: 16px;
	border: 1px solid #dfe6f1;
	background: #f8fbff;
	box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.8);
}

.destination-preview-panel strong {
	font-size: 1.05rem;
	color: #24324d;
}

.destination-preview-panel span {
	font-size: 0.88rem;
	font-weight: 700;
	letter-spacing: 0.06em;
	text-transform: uppercase;
	color: #5a74b2;
}

.destination-preview-panel p {
	font-size: 0.94rem;
	color: #5c6d88;
}

.destination-form-actions {
	display: flex;
	justify-content: flex-end;
}

.section-header {
	display: grid;
	gap: 22px;
	margin-bottom: 22px;
}

.section-header.compact {
	grid-template-columns: 1fr auto;
	align-items: start;
}

.destinations-header-block {
	gap: 24px;
}

.management-title {
	font-size: clamp(2rem, 3vw, 2.6rem);
	margin-bottom: 8px;
	font-weight: 800;
	letter-spacing: -0.03em;
}

.eyebrow {
	margin: 0 0 10px;
	font-size: 0.78rem;
	font-weight: 800;
	letter-spacing: 0.12em;
	text-transform: uppercase;
	color: #5778c7;
}

.eyebrow.subtle {
	margin-bottom: 6px;
	font-size: 0.68rem;
	color: #6f7f9c;
}

.content-panel p,
.workspace-shell p,
.login-content-panel p {
	margin: 0;
	color: #43536e;
	line-height: 1.6;
}

.lede {
	max-width: 56ch;
}

.status-panel,
.empty-state,
.segment-panel,
.table-shell {
	border: 1px solid #e1e7f1;
	border-radius: 18px;
	box-shadow: 0 16px 40px rgba(37, 51, 77, 0.08);
}

.status-panel,
.empty-state {
	padding: 16px;
	display: grid;
	gap: 8px;
	background: #f9fbff;
}

.segment-panel {
	display: flex;
	flex-wrap: wrap;
	gap: 10px;
	padding: 18px;
	background: #ffffff;
}

.segment-pill {
	display: inline-flex;
	align-items: center;
	gap: 10px;
	padding: 13px 18px;
	border-radius: 14px;
	background: #f1f4f9;
	color: #34445f;
	font-weight: 700;
}

.segment-pill span {
	display: inline-grid;
	place-items: center;
	min-width: 28px;
	height: 28px;
	padding: 0 8px;
	border-radius: 999px;
	background: rgba(255, 255, 255, 0.7);
	font-size: 0.86rem;
}

.segment-pill.active {
	background: linear-gradient(135deg, #3970f3 0%, #2854db 100%);
	color: #ffffff;
	box-shadow: 0 14px 30px rgba(47, 99, 225, 0.2);
}

.segment-pill.active span {
	background: rgba(255, 255, 255, 0.18);
	color: #ffffff;
}

.section-toolbar-row,
.toolbar,
.pagination-actions,
.card-actions {
	display: flex;
	flex-wrap: wrap;
	gap: 12px;
	align-items: center;
}

.section-toolbar-row {
	justify-content: space-between;
	gap: 18px;
}

.toolbar-search {
	flex: 1 1 420px;
}

.action-toolbar {
	justify-content: flex-end;
}

.search-input {
	min-width: min(100%, 340px);
	background: #ffffff;
}

.page-select {
	width: auto;
	min-width: 120px;
	background: #ffffff;
}

.table-shell {
	overflow: hidden;
	background: #ffffff;
}

.destination-table-head {
	display: none;
	padding: 18px 24px;
	grid-template-columns: 72px minmax(180px, 1.1fr) minmax(260px, 2fr) minmax(150px, 0.8fr) 96px;
	gap: 18px;
	font-size: 0.92rem;
	font-weight: 800;
	color: #50617e;
	border-bottom: 1px solid #dfe6f1;
	background: #fbfcff;
	text-transform: none;
}

.table-like-grid {
	gap: 0;
	background: #ffffff;
}

.destination-card {
	border-bottom: 1px solid #e7edf5;
	background: #ffffff;
}

.destination-row {
	display: grid;
	gap: 14px;
	padding: 18px 24px;
}

.destination-row:last-child {
	border-bottom: 0;
}

.destination-id-cell,
.destination-created-cell {
	font-weight: 600;
	color: #31415d;
}

.destination-copy {
	display: grid;
	gap: 6px;
}

.destination-copy h3 {
	margin: 0;
	font-size: 1.08rem;
	color: #23314b;
	font-weight: 700;
}

.destination-description-cell p,
.host-community {
	color: #52627c;
	font-size: 0.96rem;
}

.host-community {
	font-weight: 600;
}

.card-actions {
	align-items: flex-start;
	justify-content: flex-end;
	justify-self: end;
	margin-left: auto;
}

.delete-confirmation {
	display: grid;
	gap: 12px;
	padding: 14px;
	border-radius: 14px;
	background: #fff8f8;
	border: 1px solid rgba(201, 53, 53, 0.16);
}

.pagination-bar {
	display: flex;
	justify-content: space-between;
	align-items: center;
	gap: 16px;
	margin-top: 20px;
	padding-top: 16px;
	border-top: 1px solid #dfe6f1;
}

.login-footnote {
	font-weight: 500;
	color: #24324d;
}

.sr-only {
	position: absolute;
	width: 1px;
	height: 1px;
	padding: 0;
	margin: -1px;
	overflow: hidden;
	clip: rect(0, 0, 0, 0);
	white-space: nowrap;
	border: 0;
}

@media (min-width: 900px) {
	.auth-layout {
		grid-template-columns: minmax(320px, 30%) minmax(0, 1fr);
	}

	.workspace-shell {
		grid-template-columns: 280px minmax(0, 1fr);
	}

	.dashboard-grid {
		grid-template-columns: minmax(0, 1.45fr) minmax(340px, 0.95fr);
	}

	.destination-table-head {
		display: grid;
	}

	.destination-row {
		grid-template-columns: 72px minmax(180px, 1.1fr) minmax(260px, 2fr) minmax(150px, 0.8fr) 96px;
		align-items: center;
	}

	.destination-row > .card-actions {
		grid-column: -2 / -1;
	}

	.section-header.compact {
		grid-template-columns: 1fr auto;
		align-items: start;
	}

	.section-header {
		align-items: start;
	}

	.card-actions {
		justify-content: flex-end;
	}
	}

@media (max-width: 899px) {
	.workspace-shell {
		grid-template-columns: 1fr;
	}

	.workspace-sidebar {
		min-height: auto;
	}

	.workspace-header {
		padding: 16px 18px;
	}

	.workspace-header,
	.section-toolbar-row,
	.pagination-bar,
	.section-header.compact {
		grid-template-columns: 1fr;
		flex-direction: column;
		align-items: stretch;
	}

	.workspace-help-block {
		justify-items: start;
		text-align: left;
	}

	.workspace-content {
		padding: 18px;
	}

	.content-panel:first-child,
	.form-panel {
		padding: 22px;
	}

	.destination-row {
		padding: 18px;
	}

	.destination-row > .card-actions {
		width: 100%;
	}

	.toolbar-search,
	.action-toolbar,
	.login-form,
	.login-heading-block {
		width: 100%;
	}

	.action-toolbar {
		justify-content: stretch;
	}

	.action-toolbar > * {
		flex: 1 1 180px;
	}

	.destination-form-grid.two-column {
		grid-template-columns: 1fr;
	}

	.destination-card {
		grid-template-columns: minmax(0, 1fr) auto;
		align-items: start;
	}

	.form-panel {
		position: static;
	}
}

